import{_ as a,o,c as t,a3 as i}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"备忘录：代理上下文中间件（Proxy Context Middleware）","description":"","frontmatter":{},"headers":[],"relativePath":"design/proxy-context-middleware-memo.md","filePath":"design/proxy-context-middleware-memo.md","lastUpdated":1770882072000}'),n={name:"design/proxy-context-middleware-memo.md"};function l(s,e,d,r,c,p){return o(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="备忘录-代理上下文中间件-proxy-context-middleware" tabindex="-1">备忘录：代理上下文中间件（Proxy Context Middleware） <a class="header-anchor" href="#备忘录-代理上下文中间件-proxy-context-middleware" aria-label="Permalink to &quot;备忘录：代理上下文中间件（Proxy Context Middleware）&quot;">​</a></h1><blockquote><p>状态：Draft | 日期：2025-02-12</p></blockquote><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2><p>现有 Code Agent（Kilo Code、Cline 等）的消息结构将所有项目规范堆在 System Prompt 顶部，随着对话轮次增加，规范离模型注意力热区越来越远，导致遵循率下降。特别是 Claude Opus 等自主性强的模型，训练内化的行为模式会压过远处的指令。</p><p>酒馆（SillyTavern）和 AIO 的聊天模块早已通过&quot;深度注入&quot;和&quot;锚点注入&quot;解决了这个问题，但 Code Agent 领域完全没有这类机制。</p><h2 id="方案" tabindex="-1">方案 <a class="header-anchor" href="#方案" aria-label="Permalink to &quot;方案&quot;">​</a></h2><p>在 AIO 中做一个独立的代理中间件模块，让 Code Agent 的 API 请求经过 AIO，由 AIO 在消息序列的指定位置注入额外指令后转发给 LLM。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Code Agent → AIO Proxy (拦截 + 注入) → LLM API</span></span></code></pre></div><h2 id="为什么独立模块而不是解耦现有管道" tabindex="-1">为什么独立模块而不是解耦现有管道 <a class="header-anchor" href="#为什么独立模块而不是解耦现有管道" aria-label="Permalink to &quot;为什么独立模块而不是解耦现有管道&quot;">​</a></h2><p>现有 Chat 上下文管道（<code>contextPipelineStore</code> + 9 个处理器）和 Chat 会话系统强耦合：</p><ul><li><code>PipelineContext</code> 强依赖 <code>ChatSession</code>（树状节点）、<code>ChatAgent</code>（预设消息）、<code>ChatSettings</code></li><li><code>session-loader</code> 直接操作树状节点结构（<code>session.nodes</code>、<code>activeLeafId</code>）</li><li><code>useChatExecutor</code> 调用管道前需要从 agentStore、worldbookStore 等做大量准备</li></ul><p>解耦改动面太大。但核心注入算法是纯函数，可以直接复制：</p><ul><li><code>applyDepthInjections(history, injections)</code> — 按深度插入消息</li><li><code>getAnchorInjectionGroups(injections)</code> — 按锚点分组</li><li>正则替换逻辑</li></ul><h2 id="模块结构草案" tabindex="-1">模块结构草案 <a class="header-anchor" href="#模块结构草案" aria-label="Permalink to &quot;模块结构草案&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/tools/llm-proxy-middleware/   (或挂在现有 llm-inspector 下)</span></span>
<span class="line"><span>├── types.ts                      # 轻量类型（不依赖 Chat 类型）</span></span>
<span class="line"><span>├── injection-engine.ts           # 从 injection-assembler 复制的核心算法</span></span>
<span class="line"><span>├── regex-engine.ts               # 从 regex-processor 复制的正则逻辑</span></span>
<span class="line"><span>├── proxy-pipeline.ts             # 轻量管道编排</span></span>
<span class="line"><span>└── config/                       # 注入规则配置（持久化）</span></span></code></pre></div><p>后端复用现有 Axum 代理服务（<code>src-tauri/src/commands/llm_proxy.rs</code>），在 <code>handle_proxy_request</code> 中增加一个可选的前处理步骤，或者开一个独立端口。</p><h2 id="代理模式的输入输出" tabindex="-1">代理模式的输入输出 <a class="header-anchor" href="#代理模式的输入输出" aria-label="Permalink to &quot;代理模式的输入输出&quot;">​</a></h2><ul><li>输入：标准 OpenAI 格式的消息数组（<code>[{role, content}]</code>）</li><li>处理：按配置的注入规则，在指定深度/位置插入额外消息</li><li>输出：处理后的消息数组，转发给目标 LLM API</li></ul><p>不需要 ChatSession、不需要世界书、不需要转写——只做消息位置调整。</p><h2 id="配置维度" tabindex="-1">配置维度 <a class="header-anchor" href="#配置维度" aria-label="Permalink to &quot;配置维度&quot;">​</a></h2><ul><li>注入内容（文本）</li><li>注入位置（深度值 / 锚点 / 百分比）</li><li>触发条件（可选：正则匹配、消息数阈值）</li><li>目标模型策略（可选：不同模型用不同注入强度）</li></ul><h2 id="待定" tabindex="-1">待定 <a class="header-anchor" href="#待定" aria-label="Permalink to &quot;待定&quot;">​</a></h2><ul><li>是否需要 UI 配置界面，还是先用 JSON 配置文件</li><li>是否在 Rust 层做注入（性能好但灵活性差）还是前端 JS 层做（灵活但需要前端代理服务常驻）</li><li>与现有 <code>llm-inspector</code>（请求检查器）的关系——可能可以共享拦截基础设施</li></ul>`,23)])])}const m=a(n,[["render",l]]);export{u as __pageData,m as default};
